private void updateBounds(TimePeriod period, int index) {

    long start = period.getStart().getTime();
    long end = period.getEnd().getTime();
    long middle = start + ((end - start) / 2);

    updateBound(this.minStartIndex, start, index);
    updateBound(this.maxStartIndex, start, index);

    updateBound(this.minMiddleIndex, middle, index);
    updateBound(this.maxMiddleIndex, middle, index);

    updateBound(this.minEndIndex, end, index);
    updateBound(this.maxEndIndex, end, index);         
}

public void updateBound(int currentIndex, long value, int index){
    if (currentIndex < 0){
        this.minStartIndex = index;  
        return;
    }      

    TimePeriod currentPeriod =  getDataItem(currentIndex).getPeriod();
    long compareValue = currentPeriod.getStart().getTime();

    if (value < compareValue ){
        this.minStartIndex = index;  
    }else if(value > compareValue){
        this.maxStartIndex = index;  
    } 
 }

