    s.add(new SimpleTimePeriod(100L, 200L), 1.0);

    assertEquals(0, s.getMaxMiddleIndex());

    s.add(new SimpleTimePeriod(300L, 400L), 2.0);

    assertEquals(1, s.getMaxMiddleIndex());

